class Solution:
    def minTimeToReach(self, moveTime):
        n = len(moveTime)
        m = len(moveTime[0])
        INF = float('inf')
        dist = [[INF] * m for _ in range(n)]
        dist[0][0] = 0
        dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        changed = True
        while changed:
            changed = False
            for r in range(n):
                for c in range(m):
                    if dist[r][c] == INF:
                        continue
                    for dr, dc in dirs:
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < n and 0 <= nc < m:
                            nt = max(dist[r][c], moveTime[nr][nc]) + 1
                            if nt < dist[nr][nc]:
                                dist[nr][nc] = nt
                                changed = True
        return dist[n - 1][m - 1]

