var minTimeToReach = function(moveTime) {
    const n = moveTime.length;
    const m = moveTime[0].length;
    const dist = Array.from({ length: n }, () => new Array(m).fill(Infinity));
    const visited = Array.from({ length: n }, () => new Array(m).fill(false));
    dist[0][0] = 0;
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    for (let iter = 0; iter < n * m; iter++) {
        let br = -1, bc = -1, bd = Infinity;
        for (let r = 0; r < n; r++) {
            for (let c = 0; c < m; c++) {
                if (!visited[r][c] && dist[r][c] < bd) {
                    bd = dist[r][c];
                    br = r;
                    bc = c;
                }
            }
        }
        if (br === -1) break;
        visited[br][bc] = true;
        if (br === n - 1 && bc === m - 1) return bd;
        for (const [dr, dc] of dirs) {
            const nr = br + dr, nc = bc + dc;
            if (nr >= 0 && nr < n && nc >= 0 && nc < m && !visited[nr][nc]) {
                const nt = Math.max(bd, moveTime[nr][nc]) + 1;
                if (nt < dist[nr][nc]) dist[nr][nc] = nt;
            }
        }
    }
    return dist[n - 1][m - 1];
};
